def _artifact_payloads(payload, fingerprint, cache_dir, full_trace=False):
    artifacts = {
        "evidence_pack": {"query": payload["query"], "evidence": payload["evidence"]},
        "retrieval_result": {
            "fingerprint": fingerprint,
            "lexical_index": str(Path(cache_dir) / "lexical-working.sqlite3"),
            "lexical_index_cache_hit": False,
            **(payload.get("retrieval") or {}),
            "selected": [
                {
                    "id": item["id"],
                    "path": item["path"],
                    "source_refs": item["source_refs"],
                }
                for item in payload["evidence"]
            ],
        },
        "runtime_diagnostics": payload.get("runtime") or {},
    }
    if full_trace:
        artifacts["chunk_manifest"] = {
            "fingerprint": fingerprint,
            "chunks": [],
            "selected_chunk_ids": [],
        }
    return artifacts

func TestGitFingerprintManifestSkipsRepeatedHeadProbe(t *testing.T) {
	if _, err := exec.LookPath("git"); err != nil {
		t.Skip("git not available")
	}

	dir := t.TempDir()
	cacheHome := t.TempDir()
	t.Setenv("XDG_CACHE_HOME", cacheHome)
	runGitForTest(t, dir, "init")
	runGitForTest(t, dir, "config", "user.email", "test@example.com")
	runGitForTest(t, dir, "config", "user.name", "Test User")
	if err := os.WriteFile(filepath.Join(dir, "main.go"), []byte("package main\n"), 0o644); err != nil {
		t.Fatalf("write main.go: %v", err)
	}
	runGitForTest(t, dir, "add", "main.go")
	runGitForTest(t, dir, "commit", "-m", "init")

	originalRunGit := runGitFunc
	originalUserCacheDir := userCacheDirFunc
	defer func() {
		runGitFunc = originalRunGit
		userCacheDirFunc = originalUserCacheDir
	}()
	userCacheDirFunc = func() (string, error) { return cacheHome, nil }

	headCalls := 0
	runGitFunc = func(gitPath, workdir string, args ...string) (string, error) {
		if len(args) >= 2 && args[0] == "rev-parse" && args[1] == "HEAD" {
			headCalls++
		}
		return originalRunGit(gitPath, workdir, args...)
	}

	req := types.SubmitJobRequest{
		TaskType: "inspect_repo",
		InputRefs: []types.InputRef{
			{Type: "repo", URI: "file://" + dir},
		},
		OutputSchema: types.OutputSchemaRef{Name: "repo_inspection_v2"},
	}
	keyA, cacheable, err := KeyForRequest(req)
	if err != nil {
		t.Fatalf("first key for request: %v", err)
	}
	if !cacheable || keyA == "" {
		t.Fatalf("expected cacheable first key, got cacheable=%v key=%q", cacheable, keyA)
	}
	if headCalls != 1 {
		t.Fatalf("expected one head probe on first key, got %d", headCalls)
	}

	keyB, cacheable, err := KeyForRequest(req)
	if err != nil {
		t.Fatalf("second key for request: %v", err)
	}
	if !cacheable || keyB == "" {
		t.Fatalf("expected cacheable second key, got cacheable=%v key=%q", cacheable, keyB)
	}
	if keyA != keyB {
		t.Fatalf("expected stable key across repeated calls, got %q vs %q", keyA, keyB)
	}
	if headCalls != 1 {
		t.Fatalf("expected manifest reuse to skip second head probe, got %d calls", headCalls)
	}

	manifestPath := gitFingerprintManifestPath(dir, ".")
	if !strings.Contains(manifestPath, filepath.Join("local-ai-broker", "git-fingerprint-cache")) {
		t.Fatalf("unexpected manifest path %q", manifestPath)
	}
	if _, err := os.Stat(manifestPath); err != nil {
		t.Fatalf("expected manifest to exist at %q: %v", manifestPath, err)
	}
}

func toolDefinitions() []map[string]any {
	ragSpecs := tasks.RAGAliasSpecs()
	defs := make([]map[string]any, 0, len(ragSpecs)+12)
	for _, spec := range ragSpecs {
		properties := map[string]any{
			"input_refs":           inputRefsSchema(),
			"retrieval_strategies": retrievalStrategiesSchema(),
			"task_params":          map[string]any{"type": "object"},
			"constraints":          ragConstraintsSchema(),
			"execution_profile":    ragExecutionProfileSchema(),
			"idempotency_key":      map[string]any{"type": "string"},
			"wait_for_result":      map[string]any{"type": "boolean"},
			"max_wait_seconds":     map[string]any{"type": "integer"},
			"poll_interval_ms":     map[string]any{"type": "integer"},
		}
		if spec.PromptField != "" {
			properties[spec.PromptField] = map[string]any{"type": "string"}
		}
		if spec.Name == "inspect_repo" {
			properties["query"] = map[string]any{"type": "string", "maxLength": tasks.MaxInspectRepoQueryBytes}
			properties["constraints"] = inspectRepoConstraintsSchema()
			properties["mode"] = map[string]any{
				"type":    "string",
				"enum":    []string{"auto", "evidence", "answer"},
				"default": "auto",
			}
			properties["include_full_trace"] = map[string]any{"type": "boolean", "default": false}
		}
		defs = append(defs, ragToolDefinition(spec.Name, spec.Description, spec.Required, properties))
	}
	for _, spec := range coreToolDefinitions() {
		defs = append(defs, map[string]any{
			"name":        spec.name,
			"description": spec.description,
			"inputSchema": spec.inputSchema,
		})
	}
	return defs
}

func validateEvidencePackShape(payload map[string]any, requireQuery bool) error {
	if requireQuery {
		if _, ok := payload["query"].(string); !ok {
			return fmt.Errorf("payload.query must be a string")
		}
	}
	if retrieval, exists := payload["retrieval"]; exists {
		if _, ok := retrieval.(map[string]any); !ok {
			return fmt.Errorf("payload.retrieval must be an object")
		}
	}
	if retrievalPlan, exists := payload["retrieval_plan"]; exists {
		if _, ok := retrievalPlan.(map[string]any); !ok {
			return fmt.Errorf("payload.retrieval_plan must be an object")
		}
	}
	if retrievalTrace, exists := payload["retrieval_trace"]; exists {
		if _, ok := retrievalTrace.(map[string]any); !ok {
			return fmt.Errorf("payload.retrieval_trace must be an object")
		}
	}
	if evidence, exists := payload["evidence"]; exists {
		if _, ok := evidence.([]any); !ok {
			return fmt.Errorf("payload.evidence must be an array")
		}
	}
	if budget, exists := payload["budget"]; exists {
		if _, ok := budget.(map[string]any); !ok {
			return fmt.Errorf("payload.budget must be an object")
		}
	}
	return nil
}
